command:
$ErrorActionPreference = 'Stop'
Set-StrictMode -Version 2.0

$repo = [Environment]::GetEnvironmentVariable('DCOIR_REPO_ROOT','Machine')
if ([string]::IsNullOrWhiteSpace($repo)) { $repo = $env:GITHUB_WORKSPACE }
if ([string]::IsNullOrWhiteSpace($repo) -or -not (Test-Path -LiteralPath $repo -PathType Container)) {
    throw 'Unable to resolve repository root.'
}

$branch = 'codex/issue-267-powershell-engine-pester-boundary'
$expectedHead = '1da98f06532af515b480590b971e69a8309aaadf'
$expectedSourceBlobBefore = 'f6a92cb869009cf8402ee4e7c2484f94ccc6e453'
$expectedSourceBlobAfter = '27c86a430a43abd2606a35bada7a5b6afdf9d778'
$sourceRel = 'project_sources/collector/tools/build_powershell_surface_inventory.py'
$testRel = 'project_sources/collector/tools/test_build_powershell_surface_inventory_path_safety.py'
$requestId = 'exec-20260615-pr271-normalize-changed-files-002'
$requestRel = "chatgpt_staging/exec_requests/$requestId.json"
$tempRoot = $env:RUNNER_TEMP
if ([string]::IsNullOrWhiteSpace($tempRoot)) { $tempRoot = [IO.Path]::GetTempPath() }
$worktree = Join-Path $tempRoot $requestId
$patchScript = Join-Path $tempRoot "$requestId.py"
$fetchRefspec = "+refs/heads/${branch}:refs/remotes/origin/${branch}"
$pushRefspec = "HEAD:refs/heads/${branch}"

function Invoke-Git {
    param([Parameter(Mandatory=$true)][string]$Cwd, [Parameter(Mandatory=$true)][string[]]$GitArgs)
    $output = & git -C $Cwd @GitArgs 2>&1
    if ($LASTEXITCODE -ne 0) {
        throw "git $($GitArgs -join ' ') failed with exit code $LASTEXITCODE`n$output"
    }
    return $output
}

function Get-GitText {
    param([Parameter(Mandatory=$true)][string]$Cwd, [Parameter(Mandatory=$true)][string[]]$GitArgs)
    $output = Invoke-Git -Cwd $Cwd -GitArgs $GitArgs
    return (($output | Out-String).Trim())
}

function Get-TrackedBlob {
    param([Parameter(Mandatory=$true)][string]$Cwd, [Parameter(Mandatory=$true)][string]$Path)
    $line = Get-GitText -Cwd $Cwd -GitArgs @('ls-files','-s','--',$Path)
    if ([string]::IsNullOrWhiteSpace($line)) { return '' }
    return (($line -split '\s+')[1])
}

function Get-Sha256File {
    param([Parameter(Mandatory=$true)][string]$Path)
    $sha = [System.Security.Cryptography.SHA256]::Create()
    try {
        $bytes = [System.IO.File]::ReadAllBytes($Path)
        $hash = $sha.ComputeHash($bytes)
        return ([BitConverter]::ToString($hash) -replace '-', '').ToLowerInvariant()
    }
    finally {
        $sha.Dispose()
    }
}

function Get-RequiredGitToken {
    $candidates = @('DCOIR_GITHUB_FG_TOKEN','DCOIR_GITHUB_CL_TOKEN')
    foreach ($name in $candidates) {
        $value = [Environment]::GetEnvironmentVariable($name, 'Process')
        if ([string]::IsNullOrWhiteSpace($value)) { $value = [Environment]::GetEnvironmentVariable($name, 'Machine') }
        if (-not [string]::IsNullOrWhiteSpace($value)) {
            Write-Host "Using bridged GitHub token secret for PR branch push: $name"
            Write-Host "::add-mask::$value"
            return $value
        }
    }
    throw 'No bridged GitHub token secret is available for PR branch push. Refusing to push with the default workflow token because it may not trigger downstream checks.'
}

function Get-GitHubActionsRunsForHead {
    param(
        [Parameter(Mandatory=$true)][string]$Token,
        [Parameter(Mandatory=$true)][string]$HeadSha
    )
    $repoFull = $env:GITHUB_REPOSITORY
    if ([string]::IsNullOrWhiteSpace($repoFull)) { $repoFull = 'DCOIR-Collector/dcoir-collector' }
    $headers = @{
        Authorization = "Bearer $Token"
        Accept = 'application/vnd.github+json'
        'X-GitHub-Api-Version' = '2022-11-28'
        'User-Agent' = 'dcoir-chatgpt-exec-pr271'
    }
    $uri = "https://api.github.com/repos/$repoFull/actions/runs?head_sha=$HeadSha&per_page=20"
    return Invoke-RestMethod -Method Get -Uri $uri -Headers $headers
}

function Wait-GitHubActionsRunsForHead {
    param(
        [Parameter(Mandatory=$true)][string]$Token,
        [Parameter(Mandatory=$true)][string]$HeadSha,
        [int]$TimeoutSeconds = 180,
        [int]$PollSeconds = 15
    )
    $deadline = (Get-Date).ToUniversalTime().AddSeconds($TimeoutSeconds)
    do {
        $runs = Get-GitHubActionsRunsForHead -Token $Token -HeadSha $HeadSha
        if ($null -ne $runs -and $runs.total_count -gt 0) {
            return $runs
        }
        Start-Sleep -Seconds $PollSeconds
    } while ((Get-Date).ToUniversalTime() -lt $deadline)
    return $null
}

function Get-RepoFullName {
    $repoFull = $env:GITHUB_REPOSITORY
    if ([string]::IsNullOrWhiteSpace($repoFull)) { $repoFull = 'DCOIR-Collector/dcoir-collector' }
    return $repoFull
}

function Get-RequiredDownloadsDir {
    $downloads = [Environment]::GetEnvironmentVariable('DCOIR_DOWNLOADS_DIR', 'Process')
    if ([string]::IsNullOrWhiteSpace($downloads)) {
        $downloads = [Environment]::GetEnvironmentVariable('DCOIR_DOWNLOADS_DIR', 'Machine')
    }
    if ([string]::IsNullOrWhiteSpace($downloads) -or -not (Test-Path -LiteralPath $downloads -PathType Container)) {
        throw 'DCOIR_DOWNLOADS_DIR is unavailable; refusing to run without durable summary artifact storage.'
    }
    return $downloads
}

function Invoke-GitPushWithToken {
    param(
        [Parameter(Mandatory=$true)][string]$Cwd,
        [Parameter(Mandatory=$true)][string]$Token,
        [Parameter(Mandatory=$true)][string]$Refspec
    )
    $repoFull = Get-RepoFullName
    $pushUrl = "https://x-access-token:${Token}@github.com/${repoFull}.git"
    $output = & git -C $Cwd -c 'http.https://github.com/.extraheader=' push $pushUrl $Refspec 2>&1
    if ($LASTEXITCODE -ne 0) {
        $safeOutput = (($output | Out-String).Replace($Token, '[REDACTED:GITHUB_TOKEN]')).Trim()
        throw "git push to PR branch failed with exit code $LASTEXITCODE`n$safeOutput"
    }
    return $output
}

function Write-ExecutionSummary {
    param(
        [Parameter(Mandatory=$true)][string]$DownloadsDir,
        [Parameter(Mandatory=$true)][string]$Status,
        [Parameter(Mandatory=$true)][string]$ObservedRunSummary
    )
    $summaryPath = Join-Path $DownloadsDir 'pr271_changed_files_path_fix_summary.md'
    @(
        '# PR #271 changed-file path fix',
        '',
        "- request_id: $requestId",
        "- status: $Status",
        "- branch: $branch",
        "- previous_head: $expectedHead",
        "- commit_parent: $commitParent",
        "- new_head: $newHead",
        "- remote_readback_head: $remoteReadbackHead",
        "- source_blob_before: $beforeSourceBlob",
        "- source_blob_after: $afterSourceBlobStaged",
        "- test_blob_after: $afterTestBlobStaged",
        "- source_sha256_after: $sourceSha256",
        "- test_sha256_after: $testSha256",
        '',
        'Validation run in exec lane:',
        ($validationResults | ForEach-Object { "- $_" }),
        '',
        'Changed paths:',
        ($actualNames | ForEach-Object { "- $_" }),
        '',
        'Expected workflow outcome:',
        '- The PR remains Draft; Pull Request Validation may stay skipped while Draft.',
        '- Downstream draft-compatible checks must be read back separately after the branch push.',
        "- observed_runs_for_new_head: $ObservedRunSummary",
        '- This summary is not a substitute for final GitHub Actions check readback.'
    ) | Out-File -FilePath $summaryPath -Encoding utf8
}

$validationResults = New-Object System.Collections.Generic.List[string]
$changedNames = ''
$newHead = ''
$commitParent = ''
$remoteReadbackHead = ''
$observedRunSummary = 'not_polled'
$downloads = Get-RequiredDownloadsDir
$beforeSourceBlob = ''
$afterSourceBlob = ''
$afterTestBlob = ''
$sourceSha256 = ''
$testSha256 = ''

Invoke-Git -Cwd $repo -GitArgs @('fetch','origin',$fetchRefspec)
$remoteHead = Get-GitText -Cwd $repo -GitArgs @('rev-parse',"origin/$branch")
if ($remoteHead -ne $expectedHead) {
    throw "PR branch head mismatch. Expected $expectedHead but origin/$branch is $remoteHead."
}

if (Test-Path -LiteralPath $worktree) {
    Remove-Item -LiteralPath $worktree -Recurse -Force
}
Invoke-Git -Cwd $repo -GitArgs @('worktree','prune')
Invoke-Git -Cwd $repo -GitArgs @('worktree','add','--detach',$worktree,"origin/$branch")

try {
    $beforeSourceBlob = Get-TrackedBlob -Cwd $worktree -Path $sourceRel
    if ($beforeSourceBlob -ne $expectedSourceBlobBefore) {
        throw "Source blob mismatch before patch. Expected $expectedSourceBlobBefore but got $beforeSourceBlob."
    }
    if (-not [string]::IsNullOrWhiteSpace((Get-TrackedBlob -Cwd $worktree -Path $testRel))) {
        throw "Expected regression test file to be absent before patch: $testRel"
    }

    $pythonPatch = @'
from pathlib import Path
import sys

repo = Path(sys.argv[1])
source_path = repo / "project_sources/collector/tools/build_powershell_surface_inventory.py"
test_path = repo / "project_sources/collector/tools/test_build_powershell_surface_inventory_path_safety.py"

text = source_path.read_text(encoding="utf-8").replace("\r\n", "\n").replace("\r", "\n")
old = '''def normalize_changed_files(values: list[str], repo_root: Path) -> list[str]:
    normalized: list[str] = []
    for value in values:
        path = Path(value.replace("\\\\", "/"))
        if path.is_absolute():
            try:
                normalized.append(path.resolve().relative_to(repo_root.resolve()).as_posix())
            except ValueError:
                normalized.append(path.as_posix().lstrip("/"))
        else:
            normalized.append(path.as_posix())
    return sorted(dict.fromkeys(normalized))
'''
new = '''def normalize_changed_files(values: list[str], repo_root: Path) -> list[str]:
    normalized: list[str] = []
    root = repo_root.resolve()
    for value in values:
        raw = value.strip()
        if not raw:
            raise ValueError("Changed-file input must not be blank")
        slash_path = raw.replace("\\\\", "/")
        path = Path(slash_path)
        if ".." in path.parts:
            raise ValueError(f"Changed-file input must not traverse parents: {value}")
        if re.match(r"^[A-Za-z]:", slash_path) is not None and not path.is_absolute():
            raise ValueError(f"Changed-file input must be repo-relative or under repo root: {value}")
        candidate = path if path.is_absolute() else root / path
        try:
            repo_relative = candidate.resolve().relative_to(root)
        except ValueError as exc:
            raise ValueError(f"Changed-file input resolves outside repo root: {value}") from exc
        rel = repo_relative.as_posix()
        if not rel or rel == ".":
            raise ValueError(f"Changed-file input must name a file under repo root: {value}")
        normalized.append(rel)
    return sorted(dict.fromkeys(normalized))
'''
if old not in text:
    raise SystemExit("Expected normalize_changed_files block was not found.")
source_path.write_text(text.replace(old, new, 1), encoding="utf-8", newline="\n")

test_path.write_text('''#!/usr/bin/env python3
from __future__ import annotations

import importlib.util
import re
import tempfile
import unittest
from pathlib import Path

_MODULE_PATH = Path(__file__).resolve().parent / "build_powershell_surface_inventory.py"
_SPEC = importlib.util.spec_from_file_location("build_powershell_surface_inventory", _MODULE_PATH)
if _SPEC is None or _SPEC.loader is None:
    raise RuntimeError(f"Unable to load inventory module from {_MODULE_PATH}")
inventory = importlib.util.module_from_spec(_SPEC)
_SPEC.loader.exec_module(inventory)


class PowerShellSurfaceInventoryPathSafetyTests(unittest.TestCase):
    def test_changed_file_paths_preserve_valid_repo_relative_inputs(self) -> None:
        with tempfile.TemporaryDirectory() as temp:
            root = Path(temp)
            paths = inventory.normalize_changed_files([
                "project_sources\\\\collector\\\\source\\\\DCOIR_Collector.ps1",
                "./project_sources/collector/source/parts/DCOIR_Collector.01_Core.ps1",
                ".github/workflows/validate.yml",
            ], root)
        self.assertEqual(paths, [
            ".github/workflows/validate.yml",
            "project_sources/collector/source/DCOIR_Collector.ps1",
            "project_sources/collector/source/parts/DCOIR_Collector.01_Core.ps1",
        ])

    def test_changed_file_absolute_path_under_repo_becomes_relative(self) -> None:
        with tempfile.TemporaryDirectory() as temp:
            root = Path(temp).resolve()
            absolute = root / "project_sources/collector/source/DCOIR_Collector.ps1"
            paths = inventory.normalize_changed_files([absolute.as_posix()], root)
        self.assertEqual(paths, ["project_sources/collector/source/DCOIR_Collector.ps1"])

    def test_changed_file_inputs_must_not_escape_repo_root(self) -> None:
        with tempfile.TemporaryDirectory() as temp:
            root = Path(temp).resolve()
            cases = [
                "../outside.ps1",
                "project_sources/../outside.ps1",
                "/project_sources/collector/source/DCOIR_Collector.ps1",
                (root.parent / "outside.ps1").as_posix(),
                "C:\\\\outside\\\\collector.ps1",
                "C:outside\\\\collector.ps1",
                "\\\\\\\\server\\\\share\\\\collector.ps1",
                "",
            ]
            for value in cases:
                with self.subTest(value=value):
                    with self.assertRaises(ValueError):
                        inventory.normalize_changed_files([value], root)

    def test_changed_file_normalized_outputs_are_not_rooted_or_drive_qualified(self) -> None:
        with tempfile.TemporaryDirectory() as temp:
            root = Path(temp).resolve()
            paths = inventory.normalize_changed_files([
                ".github/workflows/validate.yml",
                (root / "project_sources/collector/source/DCOIR_Collector.ps1").as_posix(),
            ], root)
        for path in paths:
            with self.subTest(path=path):
                self.assertFalse(Path(path).is_absolute())
                self.assertIsNone(re.match(r"^[A-Za-z]:", path.replace("\\\\", "/")))


if __name__ == "__main__":
    raise SystemExit(unittest.main())
''', encoding="utf-8", newline="\n")
'@

    [System.IO.File]::WriteAllText($patchScript, $pythonPatch, (New-Object System.Text.UTF8Encoding($false)))
    & python $patchScript $worktree
    if ($LASTEXITCODE -ne 0) { throw "Patch script failed with exit code $LASTEXITCODE." }

    & python -m py_compile (Join-Path $worktree $sourceRel) (Join-Path $worktree $testRel)
    if ($LASTEXITCODE -ne 0) { throw "py_compile failed with exit code $LASTEXITCODE." }
    $validationResults.Add('py_compile: pass') | Out-Null

    & python (Join-Path $worktree $testRel)
    if ($LASTEXITCODE -ne 0) { throw "Path-safety unittest failed with exit code $LASTEXITCODE." }
    $validationResults.Add('path_safety_unittest: pass') | Out-Null

    Invoke-Git -Cwd $worktree -GitArgs @('diff','--check','--',$sourceRel,$testRel)
    $validationResults.Add('git_diff_check: pass') | Out-Null

    Invoke-Git -Cwd $worktree -GitArgs @('config','user.name','github-actions[bot]')
    Invoke-Git -Cwd $worktree -GitArgs @('config','user.email','41898282+github-actions[bot]@users.noreply.github.com')
    Invoke-Git -Cwd $worktree -GitArgs @('add','--',$sourceRel,$testRel)

    $afterSourceBlob = Get-TrackedBlob -Cwd $worktree -Path $sourceRel
    $afterTestBlob = Get-TrackedBlob -Cwd $worktree -Path $testRel
    if ($afterSourceBlob -ne $expectedSourceBlobAfter) { throw "Unexpected patched source blob: $afterSourceBlob" }
    $afterSourceBlobStaged = Get-GitText -Cwd $worktree -GitArgs @('hash-object','--',$sourceRel)
    $afterTestBlobStaged = Get-GitText -Cwd $worktree -GitArgs @('hash-object','--',$testRel)
    $expectedTestBlobAfter = '0c09496afa3759c707ff7497745ad1ffd1850de9'
    if ($afterSourceBlobStaged -ne $expectedSourceBlobAfter) { throw "Unexpected staged source blob: $afterSourceBlobStaged" }
    if ($afterTestBlobStaged -ne $expectedTestBlobAfter) { throw "Unexpected staged test blob: $afterTestBlobStaged" }

    Invoke-Git -Cwd $worktree -GitArgs @('diff','--cached','--check')
    $validationResults.Add('git_diff_cached_check: pass') | Out-Null
    $changedNames = Get-GitText -Cwd $worktree -GitArgs @('diff','--cached','--name-only')
    $expectedNames = @($sourceRel, $testRel)
    $actualNames = @($changedNames -split "`r?`n" | Where-Object { -not [string]::IsNullOrWhiteSpace($_) })
    $unexpectedNames = @($actualNames | Where-Object { $expectedNames -notcontains $_ })
    $missingNames = @($expectedNames | Where-Object { $actualNames -notcontains $_ })
    if ($unexpectedNames.Count -ne 0 -or $missingNames.Count -ne 0) {
        throw "Cached diff paths mismatch. Actual paths:`n$changedNames"
    }

    Invoke-Git -Cwd $repo -GitArgs @('fetch','origin',$fetchRefspec)
    $prePushHead = Get-GitText -Cwd $repo -GitArgs @('rev-parse',"origin/$branch")
    if ($prePushHead -ne $expectedHead) {
        throw "PR branch moved before push. Expected $expectedHead but origin/$branch is $prePushHead."
    }

    $commitParent = Get-GitText -Cwd $worktree -GitArgs @('rev-parse','HEAD')
    Invoke-Git -Cwd $worktree -GitArgs @(
        'commit',
        '-m','Reject unsafe changed-file paths in inventory builder',
        '-m','Guard normalize_changed_files so it only returns repo-root-contained paths, and add regression coverage for traversal, absolute, drive-qualified, UNC-like, and valid control inputs.'
    )
    $newHead = Get-GitText -Cwd $worktree -GitArgs @('rev-parse','HEAD')

    $token = Get-RequiredGitToken
    Invoke-GitPushWithToken -Cwd $worktree -Token $token -Refspec $pushRefspec | Out-Null

    Invoke-Git -Cwd $repo -GitArgs @('fetch','origin',$fetchRefspec)
    $remoteReadbackHead = Get-GitText -Cwd $repo -GitArgs @('rev-parse',"origin/$branch")
    if ($remoteReadbackHead -ne $newHead) {
        throw "Push readback mismatch. New commit $newHead but origin/$branch reads $remoteReadbackHead."
    }

    $sourceSha256 = Get-Sha256File -Path (Join-Path $worktree $sourceRel)
    $testSha256 = Get-Sha256File -Path (Join-Path $worktree $testRel)
    Write-ExecutionSummary -DownloadsDir $downloads -Status 'branch_pushed_runs_pending' -ObservedRunSummary 'pending_poll'

    $runsForHead = Wait-GitHubActionsRunsForHead -Token $token -HeadSha $newHead
    if ($null -eq $runsForHead -or $runsForHead.total_count -lt 1) {
        Write-ExecutionSummary -DownloadsDir $downloads -Status 'partial_mutation_no_runs' -ObservedRunSummary 'none_after_timeout'
        throw "No GitHub Actions workflow runs were observed for new PR branch head $newHead after polling. The patch commit landed, but validation cannot be claimed."
    }
    $observedRunSummary = (($runsForHead.workflow_runs | Select-Object -First 10 | ForEach-Object { "$($_.name):$($_.status):$($_.conclusion):$($_.id)" }) -join '; ')
    Write-ExecutionSummary -DownloadsDir $downloads -Status 'branch_pushed_runs_observed' -ObservedRunSummary $observedRunSummary

    Write-Host "Committed and pushed PR #271 path fix: $newHead"
}
finally {
    try {
        if (Test-Path -LiteralPath $worktree) {
            Invoke-Git -Cwd $repo -GitArgs @('worktree','remove','--force',$worktree) | Out-Null
        }
    } catch {
        Write-Warning "Temporary worktree cleanup failed: $($_.Exception.Message)"
    }
}
